@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">@ChildContent</div>

@code {
    /// <summary>Flex layout axis — <see cref="Lumeo.Orientation.Vertical"/> (<c>flex-col</c>,
    /// default) or <see cref="Lumeo.Orientation.Horizontal"/> (<c>flex-row</c>).</summary>
    [Parameter] public Lumeo.Orientation Direction { get; set; } = Lumeo.Orientation.Vertical;
    /// <summary>Tailwind spacing scale value rendered as <c>gap-{Gap}</c> (e.g.
    /// <c>"2"</c>, <c>"4"</c>). No gap class is emitted when null.</summary>
    [Parameter] public string? Gap { get; set; }
    /// <summary>Cross-axis alignment keyword rendered as <c>items-{Align}</c> (e.g.
    /// <c>"center"</c>, <c>"start"</c>).</summary>
    [Parameter] public string? Align { get; set; }
    /// <summary>Main-axis distribution keyword rendered as <c>justify-{Justify}</c>
    /// (e.g. <c>"between"</c>, <c>"center"</c>).</summary>
    [Parameter] public string? Justify { get; set; }
    /// <summary>Allows children to wrap onto multiple lines (<c>flex-wrap</c>). Default
    /// <c>false</c>.</summary>
    [Parameter] public bool Wrap { get; set; }
    /// <summary>The stacked children.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Additional CSS classes merged onto the root <c>div</c>.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Unmatched attributes splatted onto the root <c>div</c>.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass
    {
        get
        {
            var direction = Direction == Lumeo.Orientation.Vertical ? "flex flex-col" : "flex flex-row";
            var gap = !string.IsNullOrEmpty(Gap) ? $"gap-{Gap}" : "";
            var align = !string.IsNullOrEmpty(Align) ? $"items-{Align}" : "";
            var justify = !string.IsNullOrEmpty(Justify) ? $"justify-{Justify}" : "";
            var wrap = Wrap ? "flex-wrap" : "";
            return Cx.Merge(direction, gap, align, justify, wrap, Class);
        }
    }

}
